operation.add:

use Silkway\System\Library\{
    SeoRedirectService,
    UrlService,
    RequestService,
    ResponseService,
    ConfigService
};


/* 301 redirect SEO */
$urlService = new UrlService($this->db);
$requestService = new RequestService($this->request);
$responseService = new ResponseService($this->response);
$configService = new ConfigService($this->config);

$seoRedirectService = new SeoRedirectService(
    $urlService,
    $requestService,
    $responseService,
    $configService
);

$seoRedirectService->redirectProductToCanonical();
/* /301 redirect SEO */
